class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        int n = s.length();
        int longest = 0;
        int start = 0;
        unordered_map<char, int> charIndex;
        for (int end = 0; end < n; end++) {
            if (charIndex.count(s[end]) && charIndex[s[end]] >= start) {
                start = charIndex[s[end]] + 1;
            }
            charIndex[s[end]] = end;
            longest = max(longest, end - start + 1);
        }
        return longest;
    }
};
```
